943:      * Drain all the data for the given nodes and collate them into a list of batches that will fit
944:      * within the specified size on a per-node basis. This method attempts to avoid choosing the same
945:      * topic-node over and over.
946:      *
947:      * @param metadataSnapshot  The current cluster metadata
948:      * @param nodes             The list of node to drain
949:      * @param maxSize           The maximum number of bytes to drain
950:      * @param now               The current unix time in milliseconds
951:      * @return A list of {@link ProducerBatch} for each node specified with total size less than the
952:      * requested maxSize.
953:      */
954:     public Map<Integer, List<ProducerBatch>> drain(MetadataSnapshot metadataSnapshot, Set<Node> nodes, int maxSize, long now) {
955:         if (nodes.isEmpty())
956:             return Collections.emptyMap();
957: 
958:         Map<Integer, List<ProducerBatch>> batches = new HashMap<>();
959:         for (Node node : nodes) {
960:             List<ProducerBatch> ready = drainBatchesForOneNode(metadataSnapshot, node, maxSize, now);
961:             batches.put(node.id(), ready);
962:         }
963:         return batches;
