357:     private long sendProducerData(long now) {
358:         MetadataSnapshot metadataSnapshot = metadata.fetchMetadataSnapshot();
359:         // get the list of partitions with data ready to send
360:         RecordAccumulator.ReadyCheckResult result = this.accumulator.ready(metadataSnapshot, now);
361: 
362:         // if there are any partitions whose leaders are not known yet, force metadata update
363:         if (!result.unknownLeaderTopics.isEmpty()) {
364:             // The set of topics with unknown leader contains topics with leader election pending as well as
365:             // topics which may have expired. Add the topic again to metadata to ensure it is included
366:             // and request metadata update, since there are messages to send to the topic.
367:             for (String topic : result.unknownLeaderTopics)
368:                 this.metadata.add(topic, now);
369: 
370:             log.debug("Requesting metadata update due to unknown leader topics from the batched records: {}",
371:                 result.unknownLeaderTopics);
372:             this.metadata.requestUpdate(false);
373:         }
374: 
375:         // remove any nodes we aren't ready to send to
376:         Iterator<Node> iter = result.readyNodes.iterator();
377:         long notReadyTimeout = Long.MAX_VALUE;
378:         while (iter.hasNext()) {
379:             Node node = iter.next();
380:             if (!this.client.ready(node, now)) {
381:                 // Update just the readyTimeMs of the latency stats, so that it moves forward
382:                 // every time the batch is ready (then the difference between readyTimeMs and
383:                 // drainTimeMs would represent how long data is waiting for the node).
384:                 this.accumulator.updateNodeLatencyStats(node.id(), now, false);
385:                 iter.remove();
386:                 notReadyTimeout = Math.min(notReadyTimeout, this.client.pollDelayMs(node, now));
387:             } else {
388:                 // Update both readyTimeMs and drainTimeMs, this would "reset" the node
389:                 // latency.
390:                 this.accumulator.updateNodeLatencyStats(node.id(), now, true);
391:             }
392:         }
393: 
394:         // create produce requests
395:         Map<Integer, List<ProducerBatch>> batches = this.accumulator.drain(metadataSnapshot, result.readyNodes, this.maxRequestSize, now);
396:         addToInflightBatches(batches);
397:         if (guaranteeMessageOrder) {
398:             // Mute all the partitions drained
399:             for (List<ProducerBatch> batchList : batches.values()) {
400:                 for (ProducerBatch batch : batchList)
401:                     this.accumulator.mutePartition(batch.topicPartition);
402:             }
403:         }
404: 
405:         accumulator.resetNextBatchExpiryTime();
406:         List<ProducerBatch> expiredInflightBatches = getExpiredInflightBatches(now);
407:         List<ProducerBatch> expiredBatches = this.accumulator.expiredBatches(now);
408:         expiredBatches.addAll(expiredInflightBatches);
409: 
410:         // Reset the producer id if an expired batch has previously been sent to the broker. Also update the metrics
411:         // for expired batches. see the documentation of @TransactionState.resetIdempotentProducerId to understand why
412:         // we need to reset the producer id here.
413:         if (!expiredBatches.isEmpty())
414:             log.trace("Expired {} batches in accumulator", expiredBatches.size());
415:         for (ProducerBatch expiredBatch : expiredBatches) {
416:             String errorMessage = "Expiring " + expiredBatch.recordCount + " record(s) for " + expiredBatch.topicPartition
417:                 + ":" + (now - expiredBatch.createdMs) + " ms has passed since batch creation";
418:             failBatch(expiredBatch, new TimeoutException(errorMessage), false);
419:             if (transactionManager != null && expiredBatch.inRetry()) {
420:                 // This ensures that no new batches are drained until the current in flight batches are fully resolved.
421:                 transactionManager.markSequenceUnresolved(expiredBatch);
422:             }
423:         }
424:         sensors.updateProduceRequestMetrics(batches);
425: 
426:         // If we have any nodes that are ready to send + have sendable data, poll with 0 timeout so this can immediately
427:         // loop and try sending more data. Otherwise, the timeout will be the smaller value between next batch expiry
428:         // time, and the delay time for checking data availability. Note that the nodes may have data that isn't yet
429:         // sendable due to lingering, backing off, etc. This specifically does not include nodes with sendable data
430:         // that aren't ready to send since they would cause busy looping.
431:         long pollTimeout = Math.min(result.nextReadyCheckDelayMs, notReadyTimeout);
432:         pollTimeout = Math.min(pollTimeout, this.accumulator.nextExpiryTimeMs() - now);
433:         pollTimeout = Math.max(pollTimeout, 0);
434:         if (!result.readyNodes.isEmpty()) {
435:             log.trace("Nodes with data ready to send: {}", result.readyNodes);
436:             // if some partitions are already ready to be sent, the select time would be 0;
437:             // otherwise if some partition already has some data accumulated but not ready yet,
438:             // the select time will be the time difference between now and its linger expiry time;
439:             // otherwise the select time will be the time difference between now and the metadata expiry time;
440:             pollTimeout = 0;
441:         }
442:         sendProduceRequests(batches, now);
443:         return pollTimeout;
444:     }
